import { toast } from "sonner";

const WHATSAPP_EXTENSION_ZIP_FILENAME = "partner-connect-extension.zip";
const WHATSAPP_EXTENSION_ZIP_BASE64 =
  "";

function decodeBase64ToBytes(base64: string) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function downloadWhatsAppExtensionZip() {
  try {
    const bytes = decodeBase64ToBytes(WHATSAPP_EXTENSION_ZIP_BASE64);
    const blob = new Blob([bytes], { type: "application/zip" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = WHATSAPP_EXTENSION_ZIP_FILENAME;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
    toast.success("Estensione scaricata!");
  } catch {
    toast.error("Errore nel pacchetto ZIP");
  }
}
